```cpp
#include <memory>
#include <string>
using namespace std;

// Abstract strategy
class ShippingStrategy {
public:
    virtual double calculatePrice(double weight) const = 0;
    virtual ~ShippingStrategy() = default;
};

class StandardShipping : public ShippingStrategy {
public:
    double calculatePrice(double weight) const override {
        return weight * 5;
    }
};

class ExpressShipping : public ShippingStrategy {
public:
    double calculatePrice(double weight) const override {
        return weight * 12 + 20;
    }
};

class Package {
    double m_weight;
    string m_destination;
    // unique_ptr: the strategy object is not shared between packages,
    // each Package owns exactly one strategy at a time, and it can be
    // swapped freely at runtime via setStrategy (move semantics fit naturally).
    unique_ptr<ShippingStrategy> m_strategy;
public:
    Package(double weight, const string& destination, unique_ptr<ShippingStrategy> strategy)
        : m_weight(weight), m_destination(destination), m_strategy(std::move(strategy)) {}

    // Package owns a unique_ptr member -> not copyable by default (compiler
    // would delete the copy ctor anyway); we make this explicit:
    Package(const Package&) = delete;
    Package& operator=(const Package&) = delete;

    double getPrice() const {
        return m_strategy->calculatePrice(m_weight);
    }

    void setStrategy(unique_ptr<ShippingStrategy> strategy) {
        m_strategy = std::move(strategy);
    }

    const string& getDestination() const { return m_destination; }
};
```

**Design pattern: Strategy.**
The requirement is to encapsulate an interchangeable *whole algorithm* (the entire price-calculation formula) behind a common interface, and to be able to **swap the algorithm at runtime** on an existing object without changing its identity or wrapping it in another layer. This is exactly the Strategy pattern's purpose: the context (`Package`) holds a reference/pointer to a strategy object and delegates the computation to it, and `setStrategy` lets the client swap the entire behavior.

**Why not Decorator:** Decorator is meant for *adding a layer on top of* an existing computed value (e.g. wrapping a base price with an additional surcharge object that adds to whatever the wrapped object returns), and decorators are naturally stackable/composable, with the order of wrapping affecting the result. Here we don't want to add a surcharge on top of an existing algorithm - we want to **replace the whole computation** with a different, unrelated formula, and there is no notion of stacking multiple algorithms together. Strategy is the correct fit because it models 'one algorithm out of a family, chosen/replaced as a unit,' not 'one layer among several stacked layers.'

```cpp
#include <string>
#include <vector>
#include <memory>
#include <exception>
using namespace std;

// ---------- Part A ----------
class FSItem {
    const string m_name;
public:
    explicit FSItem(const string& name) : m_name(name) {}
    virtual ~FSItem() = default;

    const string& getName() const { return m_name; }
    virtual long getSize() const = 0;
};

// ---------- Part B ----------
class File : public FSItem {
    long m_size;
public:
    File(const string& name, long size) : FSItem(name), m_size(size) {}
    long getSize() const override { return m_size; }
};

// ---------- custom exceptions ----------
class DuplicateItemName : public exception {
    string m_msg;
public:
    explicit DuplicateItemName(const string& name)
        : m_msg("Duplicate item name: " + name) {}
    const char* what() const noexcept override { return m_msg.c_str(); }
};

class ItemNotFound : public exception {
    string m_msg;
public:
    explicit ItemNotFound(const string& name)
        : m_msg("Item not found: " + name) {}
    const char* what() const noexcept override { return m_msg.c_str(); }
};

// ---------- Part C ----------
// Folder is the Composite: it holds FSItem's (Files or sub-Folders)
// by unique_ptr, i.e. it exclusively owns them. Because unique_ptr
// cannot be copied, Folder (and thus the whole tree) is automatically
// non-copyable -- exactly what we want, since a naive default copy of
// a vector<unique_ptr<FSItem>> would not even compile, preventing an
// accidental shallow copy of the tree. (If deep-copy semantics were
// required, a virtual clone() -- Prototype pattern -- would be added.)
class Folder : public FSItem {
    vector<unique_ptr<FSItem>> m_items;
public:
    explicit Folder(const string& name) : FSItem(name) {}

    // non-copyable: unique_ptr members already forbid the default
    // copy ctor/assignment from being generated, but we make this
    // explicit for clarity.
    Folder(const Folder&) = delete;
    Folder& operator=(const Folder&) = delete;

    void addItem(unique_ptr<FSItem> item) {
        for (const auto& existing : m_items) {
            if (existing->getName() == item->getName()) {
                throw DuplicateItemName(item->getName());
            }
        }
        m_items.push_back(std::move(item));
    }

    FSItem& getItem(const string& name) const {
        for (const auto& item : m_items) {
            if (item->getName() == name) {
                return *item;
            }
        }
        throw ItemNotFound(name);
    }

    long getSize() const override {
        long total = 0;
        for (const auto& item : m_items) {
            total += item->getSize();   // virtual dispatch: recurses
                                          // into sub-Folders automatically
        }
        return total;
    }
};
```

**חלק ד' - דפוס העיצוב:**

המבנה `FSItem`/`File`/`Folder` מממש את דפוס ה-**Composite**. `Folder` היא בעצמה `FSItem` (יורשת ממנה) ומחזיקה אוסף של `FSItem` נוספים (קבצים ותיקיות-משנה כאחד), כך שלקוח הקורא ל-`getSize()` על `Folder` אינו צריך לדעת אם הוא מטפל בעלה בודד (`File`) או בתת-עץ שלם (`Folder`) - הקריאה מתפשטת רקורסיבית באמצעות dispatch וירטואלי בלבד.

זהו **לא** דפוס Decorator: ב-Decorator עטיפה אחת עוטפת בדיוק אובייקט (רכיב) אחד בלבד ומוסיפה/משנה התנהגות סביבו בצורה שתלויה בסדר העטיפות (למשל תוספת שמוסיפה מחיר קבוע), ואין לה מושג של "אוסף פריטים" בעל שמות ייחודיים שניתן להוסיף/לשלוף לפיהם. כאן לעומת זאת יש מבנה עץ אמיתי בעל-רבים (תיקיה מכילה **מספר** ילדים), עם ממשק אחיד לכל צומת (עלה או פנימי) - זהו בדיוק המקרה הקלאסי של Composite.

```cpp
#include <string>
#include <unordered_map>
#include <memory>
#include <stdexcept>
#include <utility>
using namespace std;

// ---------- (א) Package hierarchy ----------
class Package {
    string m_name;
    double m_weight;
public:
    Package(const string& name, double weight) : m_name(name), m_weight(weight) {
        if (weight <= 0) {
            throw invalid_argument("weight must be positive");
        }
    }

    virtual ~Package() = default; // safe polymorphic destruction

    virtual double getShippingCost() const = 0; // pure virtual - varies per subclass

    const string& getName() const { return m_name; }

protected:
    double getWeight() const { return m_weight; }
};

class StandardPackage : public Package {
public:
    StandardPackage(const string& name, double weight) : Package(name, weight) {}

    double getShippingCost() const override {
        return getWeight() * 5.0;
    }
};

class FragilePackage : public Package {
public:
    FragilePackage(const string& name, double weight) : Package(name, weight) {}

    double getShippingCost() const override {
        return getWeight() * 5.0 + 20.0;
    }
};

// ---------- (ב) custom exceptions ----------
class DuplicatePackageException : public exception {
    string m_msg;
public:
    explicit DuplicatePackageException(const string& name)
        : m_msg("Package already exists: " + name) {}
    const char* what() const noexcept override { return m_msg.c_str(); }
};

class PackageNotFoundException : public exception {
    string m_msg;
public:
    explicit PackageNotFoundException(const string& name)
        : m_msg("Package not found: " + name) {}
    const char* what() const noexcept override { return m_msg.c_str(); }
};

// ---------- (ג) managing container ----------
class Warehouse {
    // map by name for O(1) average lookup/insert/erase
    unordered_map<string, unique_ptr<Package>> m_packages;
public:
    Warehouse() = default;

    // Warehouse uniquely owns its Packages via unique_ptr => non-copyable by default
    // (unique_ptr has no copy ctor, so the compiler-generated copy ops are
    //  already implicitly deleted; declaring this explicitly documents intent).
    Warehouse(const Warehouse&) = delete;
    Warehouse& operator=(const Warehouse&) = delete;

    // move is fine and comes for free (defaults would work), state it explicitly:
    Warehouse(Warehouse&&) = default;
    Warehouse& operator=(Warehouse&&) = default;

    void addPackage(unique_ptr<Package> pkg) {
        const string& name = pkg->getName();
        if (m_packages.find(name) != m_packages.end()) {
            throw DuplicatePackageException(name);
        }
        m_packages.emplace(name, std::move(pkg));
    }

    double getShippingCost(const string& name) const {
        auto it = m_packages.find(name);
        if (it == m_packages.end()) {
            throw PackageNotFoundException(name);
        }
        return it->second->getShippingCost();
    }

    unique_ptr<Package> removePackage(const string& name) {
        auto it = m_packages.find(name);
        if (it == m_packages.end()) {
            throw PackageNotFoundException(name);
        }
        unique_ptr<Package> removed = std::move(it->second);
        m_packages.erase(it);
        return removed; // ownership transferred to the caller
    }

    double getTotalShippingCost() const {
        double total = 0.0;
        for (const auto& entry : m_packages) {
            total += entry.second->getShippingCost();
        }
        return total;
    }

    // destructor is implicit: unique_ptr members clean themselves up,
    // no raw owning pointers => Rule of 3 defaults (dtor) are sufficient here.
};
```

## סעיף א' - היררכיה בסיסית

```cpp
class Package {
protected:
    double weight;
public:
    explicit Package(double w) : weight(w) {}
    virtual ~Package() = default;
    virtual double getCost() const = 0;
};

class InternalPackage : public Package {
public:
    explicit InternalPackage(double w) : Package(w) {}
    double getCost() const override {
        return 20.0 + 2.0 * weight;
    }
};

class ExternalPackage : public Package {
    double customsFee;
public:
    ExternalPackage(double w, double customsFee)
        : Package(w), customsFee(customsFee) {}
    double getCost() const override {
        return 50.0 + 5.0 * weight + customsFee;
    }
};
```

## סעיף ב' - Factory Method

```cpp
class UnsupportedPackageType : public std::exception {
    std::string msg;
public:
    explicit UnsupportedPackageType(const std::string& type)
        : msg("Unsupported package type: " + type) {}
    const char* what() const noexcept override { return msg.c_str(); }
};

class PackageFactory {
public:
    static std::unique_ptr<Package> createPackage(const std::string& type,
                                                   double weight,
                                                   double customsFee = 0.0) {
        if (type == "internal") {
            return std::make_unique<InternalPackage>(weight);
        } else if (type == "external") {
            return std::make_unique<ExternalPackage>(weight, customsFee);
        } else {
            throw UnsupportedPackageType(type);
        }
    }
};
```

הערה: החתימה מרכזת את לוגיקת הבחירה במקום אחד; קוד הלקוח קורא ל-`PackageFactory::createPackage(...)` ואינו צריך לדעת על `InternalPackage`/`ExternalPackage` כלל, מה שמאפשר להוסיף סוגים חדשים ללא שינוי בקוד הקורא (רק ב-Factory עצמו - עדיין מפר את OCP באופן חלקי, נקודה שממשיכה לסעיף ג').

## סעיף ג' - Abstract Factory

ה-Factory הפשוט (Factory Method) מתאים ליצירת **מוצר בודד** לפי שם/סוג. כאן יש צורך ביצירת **משפחה שלמה ועקבית** של מוצרים קשורים זה לזה (`Package`, `Packaging`, `Tracker`) כך שכולם מגיעים מאותה "משפחה" (Express או Standard) - זהו בדיוק המקרה הקלאסי של **Abstract Factory**.

Factory פשוט אינו מספיק כי:
- הוא יוצר אובייקט בודד מסוג אחד, ואין לו מנגנון לאכוף "עקביות" בין כמה מוצרים שונים שנוצרים יחד.
- אם נשתמש בשני Factory-ים נפרדים (אחד ל-Package, אחד ל-Packaging, אחד ל-Tracker) - שום דבר לא מונע מלקוח "לערבב" ולבחור Packaging של Express יחד עם Tracker של Standard בטעות.

מבנה הפתרון (Abstract Factory):

```cpp
class ShippingFamilyFactory {
public:
    virtual ~ShippingFamilyFactory() = default;
    virtual std::unique_ptr<Package>   createPackage(double weight) const = 0;
    virtual std::unique_ptr<Packaging> createPackaging() const = 0;
    virtual std::unique_ptr<Tracker>   createTracker() const = 0;
};

class ExpressFamilyFactory : public ShippingFamilyFactory {
public:
    std::unique_ptr<Package>   createPackage(double weight) const override;   // ExpressPackage
    std::unique_ptr<Packaging> createPackaging() const override;              // ExpressPackaging
    std::unique_ptr<Tracker>   createTracker() const override;                // GpsTracker
};

class StandardFamilyFactory : public ShippingFamilyFactory {
public:
    std::unique_ptr<Package>   createPackage(double weight) const override;   // StandardPackage
    std::unique_ptr<Packaging> createPackaging() const override;              // StandardPackaging
    std::unique_ptr<Tracker>   createTracker() const override;                // BasicTracker
};
```

כעת הלקוח מקבל אובייקט אחד בטיפוס `ShippingFamilyFactory&` (למשל לפי בחירת המשתמש ב-runtime), וכל שלושת המוצרים שהוא יוצר דרכו שייכים תמיד לאותה משפחה - העקביות מובטחת מבנית ולא תלויה במשמעת של קוד הלקוח.

## סעיף ד' - הרסן וירטואלי

`Package` חייבת הרסן וירטואלי כי היא נמחקת פולימורפית: כאשר `unique_ptr<Package>` (המצביע בפועל, ב-runtime, ל-`ExternalPackage` למשל) יוצא מהתחום, ה-`unique_ptr` קורא ל-`delete` על מצביע מסוג `Package*`. ללא הרסן וירטואלי, הקומפיילר יקשור את הקריאה סטטית להרסן של `Package` בלבד (**Static/Early binding**), כך שהרסן של `ExternalPackage` (וכל ההרסים ההיררכיים שלו, כולל שדה `customsFee` אם היה מכיל משאב דינמי) **לא ייקרא כלל** - התנהגות בלתי מוגדרת (Undefined Behavior) בפועל: לרוב יתבצע דליפת זיכרון/משאבים (resource leak) של השדות הייחודיים למחלקה היורשת, ובמקרים מסוימים קריסה או שחיתות זיכרון (memory corruption) אם המחלקה היורשת מנהלת משאבים בעצמה.

questions.prompt_he:
בשאלה זו תתכננו ותממשו מערכת פקודות עבור רחפן (Drone).

נתונה המחלקה הבאה (מוגדרת עבורכם, אין לשנותה):
```cpp
class Drone {
    int m_x, m_y, m_altitude;
public:
    Drone() : m_x(0), m_y(0), m_altitude(0) {}
    void move(int dx, int dy) { m_x += dx; m_y += dy; }
    void changeAltitude(int delta) { m_altitude += delta; }
    int getX() const { return m_x; }
    int getY() const { return m_y; }
    int getAltitude() const { return m_altitude; }
};
```

המערכת צריכה לתמוך ב'תוכניות טיסה' (FlightPlan): רצף פקודות שכל אחת מבצעת פעולה על הרחפן (למשל MoveCommand, AscendCommand, DescendCommand). **אותה פקודה עשויה להופיע כמה פעמים ברצף, בכל סדר**, ותוכניות טיסה חדשות (טיפוסי פקודה נוספים) עשויות להתווסף בעתיד מבלי לשנות את מחלקת ה-FlightPlan. בנוסף, לאחר הרצת כל התוכנית יש אפשרות לבצע Undo צעד-אחד-אחורה (לבטל את הפעולה האחרונה שבוצעה על הרחפן).

ממומשו הנדרש:

**סעיף א' (5 נק'):** הסבירו במשפט אחד מדוע Command הוא הפטרן המתאים כאן, ולא Strategy ולא Decorator (התייחסו לדרישה של חזרה על אותה פעולה מספר פעמים ולדרישת ה-Undo).

**סעיף ב' (15 נק'):** ממשו מחלקת בסיס אבסטרקטית `DroneCommand` עם מתודה וירטואלית טהורה `execute(Drone&)` ומתודה וירטואלית טהורה `undo(Drone&)`, ו-destructor וירטואלי. ממשו שתי מחלקות קונקרטיות: `MoveCommand` (מזיז ב-(dx,dy), וה-undo מזיז בחזרה) ו-`AscendCommand` (משנה גובה ב-delta, וה-undo משנה בחזרה).

**סעיף ג' (15 נק'):** ממשו מחלקה `FlightPlan` שמנהלת `vector<unique_ptr<DroneCommand>>` (בעלות בלעדית על הפקודות). מתודות:
- `void addCommand(unique_ptr<DroneCommand> cmd)` - מוסיפה פקודה לסוף הרצף.
- `void executeAll(Drone& d)` - מריצה את כל הפקודות לפי הסדר, ותוך כדי כך שומרת מחסנית היסטוריה פנימית לצורך undo.
- `void undoLast(Drone& d)` - מבטלת את הפעולה האחרונה שבוצעה על הרחפן (זורקת `NoCommandToUndo` אם ההיסטוריה ריקה).

ודאו ש-`FlightPlan` אינה ניתנת להעתקה (מאחר וכל פקודה בבעלות בלעדית).

**סעיף ד' (5 נק'):** מהם התנאים על T (אם היינו הופכים את `DroneCommand` לתבנית גנרית לפי סוג הרכב, למשל)? התייחסו קצרה בלבד - אין צורך לממש.

questions.model_solution:
### סעיף א'
Command מתאים כי כל פקודה היא אובייקט עצמאי שמכיל את הפעולה ואת דרך ביטולה, וניתן להוסיף אותה **מספר פעמים ובכל סדר** לרצף (בניגוד ל-Strategy, שמחליף אלגוריתם יחיד ולא אמור לחזור על עצמו כרצף), ו-Decorator עוטף ומשנה ערך מחושב יחיד באופן מקונן ולא נועד לספק פעולת `undo` סימטרית לכל שלב.

### סעיף ב'-ג'
```cpp
#include <vector>
#include <memory>
#include <stdexcept>
using namespace std;

class DroneCommand {
public:
    virtual void execute(Drone& d) = 0;
    virtual void undo(Drone& d) = 0;
    virtual ~DroneCommand() = default;
};

class MoveCommand : public DroneCommand {
    int m_dx, m_dy;
public:
    MoveCommand(int dx, int dy) : m_dx(dx), m_dy(dy) {}
    void execute(Drone& d) override { d.move(m_dx, m_dy); }
    void undo(Drone& d) override { d.move(-m_dx, -m_dy); }
};

class AscendCommand : public DroneCommand {
    int m_delta;
public:
    explicit AscendCommand(int delta) : m_delta(delta) {}
    void execute(Drone& d) override { d.changeAltitude(m_delta); }
    void undo(Drone& d) override { d.changeAltitude(-m_delta); }
};

class NoCommandToUndo : public std::exception {
public:
    const char* what() const noexcept override { return "No command to undo"; }
};

class FlightPlan {
    vector<unique_ptr<DroneCommand>> m_commands;
    vector<DroneCommand*> m_history; // non-owning, for undo order
public:
    FlightPlan() = default;
    FlightPlan(const FlightPlan&) = delete;
    FlightPlan& operator=(const FlightPlan&) = delete;

    void addCommand(unique_ptr<DroneCommand> cmd) {
        m_commands.push_back(std::move(cmd));
    }

    void executeAll(Drone& d) {
        for (auto& cmd : m_commands) {
            cmd->execute(d);
            m_history.push_back(cmd.get());
        }
    }

    void undoLast(Drone& d) {
        if (m_history.empty()) throw NoCommandToUndo();
        DroneCommand* last = m_history.back();
        m_history.pop_back();
        last->undo(d);
    }
};
```

**הערות מימוש:**
- `FlightPlan` מחזיקה בבעלות בלעדית (`unique_ptr`) על הפקודות ולכן חייבת להיות non-copyable — אנו מוחקים במפורש את בנאי/אופרטור ההעתקה (למרות ש-`vector<unique_ptr<T>>` כשלעצמו כבר לא ניתן להעתקה, מומלץ מפורשות לצורך תיעוד וקריאות).
- `m_history` הוא `vector` של מצביעים גולמיים **לא-בעלים** (non-owning) - רק כדי לזכור את סדר ההרצה בפועל לצורך undo; הבעלות האמיתית נשארת ב-`m_commands`.
- ה-destructor הדיפולטיבי מספיק כי כל האיברים הם STL/smart-pointer (אין מצביע גולמי בבעלות) - Rule of 3 לא נדרש כאן במפורש.

### סעיף ד'
אם `DroneCommand` היה תבנית גנרית לפי סוג רכב `T`, היינו דורשים מ-`T` לחשוף את המתודות שהפקודות קוראות (כאן: `move`, `changeAltitude` וכד'), כלומר ממשק מינימלי תואם - לא בהכרח ירושה, אלא duck-typing ברמת הקומפילציה (concept/requirement) של המתודות הרלוונטיות.

questions.prompt_he:
בשאלה זו תתכננו ותממשו מדרג מחלקות פולימורפי ומיכל השומר עותקים עמוקים שלו.

נתונה מחלקת בסיס מופשטת `Shape` המייצגת צורה גאומטרית:
```cpp
class Shape {
public:
    virtual ~Shape() = default;
    virtual double getArea() const = 0;
    virtual Shape* clone() const = 0;
};
```

**סעיף א' (10 נק'):** ממשו שתי מחלקות קונקרטיות היורשות מ-`Shape`:
1. `Circle` - מחזיקה רדיוס (`double`), `getArea()` מחזירה π*r².
2. `Rectangle` - מחזיקה רוחב וגובה (`double`), `getArea()` מחזירה width*height.

על כל מחלקה לממש את `getArea()` ואת `clone()` (המחזירה מצביע חדש למופע מאותו סוג דינמי, בעל אותם נתונים).

**סעיף ב' (12 נק'):** ממשו מחלקה `ShapeCollection` המחזיקה אוסף צורות (`vector<unique_ptr<Shape>>`), עם הפעולות:
- `void addShape(unique_ptr<Shape> s)` - מוסיפה צורה לאוסף (מעבירה בעלות).
- `double getTotalArea() const` - מחזירה את סכום השטחים של כל הצורות באוסף.
- בנאי העתקה (copy constructor) שיוצר **עותק עמוק** של האוסף - כל צורה תשוכפל בעזרת `clone()`, כך שלשני האובייקטים (`ShapeCollection`) לא תהיה בעלות משותפת על אף צורה.
- מפעיל השמה (`operator=`) תקין (Rule of 3/5 מלא, exception-safe, כולל טיפול נכון במקרה של self-assignment).

**סעיף ג' (8 נק'):** הסבירו (2-3 משפטים) מדוע לא ניתן להשתמש בבנאי העתקה רגיל (copy constructor) של `Shape` כדי לשכפל אובייקט דרך מצביע/הפניה למחלקת הבסיס, ומדוע יש צורך במתודה וירטואלית `clone()`. איזו תבנית עיצוב (design pattern) המתודה `clone()` מממשת?

questions.model_solution:
### סעיף א'
```cpp
class Circle : public Shape {
    double radius;
public:
    explicit Circle(double r) : radius(r) {}
    double getArea() const override {
        return M_PI * radius * radius;
    }
    Shape* clone() const override {
        return new Circle(*this);
    }
};

class Rectangle : public Shape {
    double width, height;
public:
    Rectangle(double w, double h) : width(w), height(h) {}
    double getArea() const override {
        return width * height;
    }
    Shape* clone() const override {
        return new Rectangle(*this);
    }
};
```

### סעיף ב'
```cpp
class ShapeCollection {
    vector<unique_ptr<Shape>> shapes;
public:
    ShapeCollection() = default;

    void addShape(unique_ptr<Shape> s) {
        shapes.push_back(std::move(s));
    }

    double getTotalArea() const {
        double total = 0.0;
        for (const auto& s : shapes) {
            total += s->getArea();
        }
        return total;
    }

    // Deep copy constructor - clones every shape via virtual clone()
    ShapeCollection(const ShapeCollection& other) {
        for (const auto& s : other.shapes) {
            shapes.push_back(unique_ptr<Shape>(s->clone()));
        }
    }

    // Copy-and-swap: exception-safe, handles self-assignment naturally
    ShapeCollection& operator=(const ShapeCollection& other) {
        if (this != &other) {
            ShapeCollection temp(other); // deep copy, may throw - *this unaffected if it does
            shapes = std::move(temp.shapes); // noexcept swap of vectors
        }
        return *this;
    }

    // unique_ptr members => default move ctor/move assignment/destructor are correct and sufficient
    ShapeCollection(ShapeCollection&&) = default;
    ShapeCollection& operator=(ShapeCollection&&) = default;
    ~ShapeCollection() = default;
};
```

### סעיף ג'
בנאי העתקה (copy constructor) אינו יכול להיות וירטואלי בשפת C++, ולכן קריאה כמו `new Shape(*ptr)` תמיד תבחר את הבנאי של `Shape` (הסטטי) ולא של הטיפוס הדינמי בפועל (`Circle`/`Rectangle`), כלומר תיצור עותק חלקי (slicing) ותאבד את השדות הייחודיים למחלקה הנגזרת. הפתרון הוא הגדרת מתודה **וירטואלית** `clone()` בבסיס, שכל מחלקה נגזרת מממשת כ-`new Derived(*this)` תוך קריאה לבנאי ההעתקה **הנכון** של הטיפוס שלה - הקריאה הפולימורפית ל-clone() דרך מצביע/הפניה לבסיס מבטיחה שיווצר עותק מהטיפוס הדינמי הנכון, ללא slicing.

תבנית העיצוב המיושמת היא **Prototype** (המכונה גם 'virtual clone idiom') - יצירת עותקים חדשים של אובייקט על ידי שכפול מופע קיים (ה'אב-טיפוס') במקום בנייתו מחדש דרך שם המחלקה הקונקרטית.

```cpp
#include <memory>
#include <exception>
#include <utility>

class EmptyStackException : public std::exception {
public:
    const char* what() const noexcept override {
        return "Stack is empty";
    }
};

template <class T>
class Stack {
private:
    struct Node {
        T value;
        std::unique_ptr<Node> next;
        Node(const T& v, std::unique_ptr<Node> n)
            : value(v), next(std::move(n)) {}
    };

    std::unique_ptr<Node> m_head;
    size_t m_size;

    // Helper: deep-copies the chain starting at 'src' (may be nullptr).
    // Exception-safe: if 'new Node' or the T copy throws partway through,
    // everything allocated so far is automatically released because it
    // is owned by unique_ptr's that go out of scope / are destroyed by
    // the exception unwinding (no manual delete needed, no leaks).
    static std::unique_ptr<Node> cloneChain(const Node* src) {
        if (!src) return nullptr;
        return std::make_unique<Node>(src->value, cloneChain(src->next.get()));
    }

public:
    Stack() : m_head(nullptr), m_size(0) {}

    // Destructor: NOT strictly necessary to write explicitly.
    // unique_ptr's destructor recursively destroys next, next->next, ...
    // so the compiler-generated destructor already frees the whole chain
    // correctly (no raw owning pointers here).
    ~Stack() = default;

    // Copy constructor: deep copy of the entire chain.
    Stack(const Stack& other)
        : m_head(cloneChain(other.m_head.get())), m_size(other.m_size) {}

    // Copy assignment: copy-and-swap idiom for strong exception safety.
    Stack& operator=(const Stack& other) {
        if (this != &other) {
            std::unique_ptr<Node> newHead = cloneChain(other.m_head.get());
            // Only after the deep copy succeeded do we commit the change:
            m_head = std::move(newHead);
            m_size = other.m_size;
        }
        return *this;
    }

    void push(const T& value) {
        m_head = std::make_unique<Node>(value, std::move(m_head));
        ++m_size;
    }

    T pop() {
        if (isEmpty()) throw EmptyStackException();
        T result = std::move(m_head->value);
        m_head = std::move(m_head->next);
        --m_size;
        return result;
    }

    const T& top() const {
        if (isEmpty()) throw EmptyStackException();
        return m_head->value;
    }

    bool isEmpty() const { return m_size == 0; }
    size_t size() const { return m_size; }
};
```

**הסברים (חלק 8):**

- הבנאי/אופרטור ההשמה שנוצרים אוטומטית עבור `unique_ptr` **מחוקים (deleted)** - `unique_ptr` אינו ניתן להעתקה מעצם הגדרתו (בעלות בלעדית). לכן קומפיילר לא יכול היה בכלל לייצר בנאי העתקה עובד עבור `Stack<T>` - יש חובה לכתוב אותו ידנית, ולבצע העתקה עמוקה צומת-אחר-צומת (ולא רק להעתיק את המצביע `m_head`, שהיה גורם לשגיאת קומפילציה/שיתוף בעלות).
- **דרישות על T**: בנאי העתקה (copy constructor) עבור `T` (משמש ב-`push` וב-`cloneChain`), ורצוי גם בנאי ברירת מחדל/הזזה (לא הכרחי כאן כי לא השתמשנו ב-`T()` בשום מקום). אין דרישה לאופרטור השוואה או סידור.
- **הרסן**: אינו נחוץ באופן מפורש כי כל הזיכרון מנוהל על ידי `unique_ptr` (חבר STL/smart pointer) - ברירת המחדל של הקומפיילר הורסת את השרשרת רקורסיבית כראוי, ללא דליפות.
- שימו לב ש-`cloneChain` הרקורסיבי בטוח מבחינת חריגות: אם זריקת חריגה מתרחשת במהלך יצירת צומת כלשהו (למשל `bad_alloc` או חריגה מבנאי ההעתקה של `T`), כל ה-`unique_ptr` שכבר נוצרו במחסנית הקריאות (call stack) משוחררים אוטומטית תוך כדי גלגול החריגה (stack unwinding), כך שאין דליפת זיכרון והאובייקט המקורי (`other`) אינו נפגע.

```cpp
#include <cstddef>
#include <stdexcept>

template <class T>
class RingLog {
    T* m_data;
    size_t m_capacity;
    size_t m_count;   // number of valid elements currently stored (0..capacity)
    size_t m_head;    // index of the oldest element

    // logical index i (0 = oldest) -> physical index in m_data
    size_t physIndex(size_t i) const { return (m_head + i) % m_capacity; }

public:
    explicit RingLog(size_t capacity)
        : m_data(nullptr), m_capacity(capacity), m_count(0), m_head(0) {
        if (capacity == 0) throw std::invalid_argument("capacity must be positive");
        m_data = new T[capacity];
    }

    RingLog(const RingLog& other)
        : m_data(nullptr), m_capacity(other.m_capacity),
          m_count(other.m_count), m_head(other.m_head) {
        m_data = new T[m_capacity];
        try {
            for (size_t i = 0; i < m_capacity; ++i) m_data[i] = other.m_data[i];
        } catch (...) {
            delete[] m_data;
            throw;
        }
    }

    RingLog& operator=(const RingLog& other) {
        if (this == &other) return *this;
        T* newData = new T[other.m_capacity];
        try {
            for (size_t i = 0; i < other.m_capacity; ++i) newData[i] = other.m_data[i];
        } catch (...) {
            delete[] newData;
            throw;
        }
        delete[] m_data;
        m_data = newData;
        m_capacity = other.m_capacity;
        m_count = other.m_count;
        m_head = other.m_head;
        return *this;
    }

    ~RingLog() { delete[] m_data; }

    void push(const T& item) {
        if (m_count < m_capacity) {
            m_data[physIndex(m_count)] = item;
            ++m_count;
        } else {
            // buffer full: overwrite the oldest slot, then advance head
            m_data[m_head] = item;
            m_head = (m_head + 1) % m_capacity;
        }
    }

    size_t size() const { return m_count; }

    class iterator {
        RingLog<T>* m_owner;
        size_t m_pos; // logical position, 0..m_owner->size()
        iterator(RingLog<T>* owner, size_t pos) : m_owner(owner), m_pos(pos) {}
        friend class RingLog<T>;
    public:
        iterator& operator++() { ++m_pos; return *this; }
        bool operator!=(const iterator& o) const {
            return m_owner != o.m_owner || m_pos != o.m_pos;
        }
        T& operator*() { return m_owner->m_data[m_owner->physIndex(m_pos)]; }
        const T& operator*() const { return m_owner->m_data[m_owner->physIndex(m_pos)]; }
    };

    class const_iterator {
        const RingLog<T>* m_owner;
        size_t m_pos;
        const_iterator(const RingLog<T>* owner, size_t pos) : m_owner(owner), m_pos(pos) {}
        friend class RingLog<T>;
    public:
        const_iterator& operator++() { ++m_pos; return *this; }
        bool operator!=(const const_iterator& o) const {
            return m_owner != o.m_owner || m_pos != o.m_pos;
        }
        const T& operator*() const { return m_owner->m_data[m_owner->physIndex(m_pos)]; }
    };

    iterator begin() { return iterator(this, 0); }
    iterator end()   { return iterator(this, m_count); }
    const_iterator begin() const { return const_iterator(this, 0); }
    const_iterator end()   const { return const_iterator(this, m_count); }
};
```

**דרישות מהטיפוס `T`:**
`T` חייב לתמוך בבנאי ברירת מחדל (default constructor) - כי `new T[capacity]` יוצר את כל האיברים מראש - וכן באופרטור השמה (`operator=`, ל-`push` ולהעתקה). אין דרישה ל-`operator==` או `operator<` שכן לא בוצעה השוואה או מיון בין אלמנטים.

**Rule of 3:**
כן, יש צורך במימוש ידני של בנאי העתקה, אופרטור השמה והורס, מכיוון שהמחלקה מחזיקה מצביע גולמי בבעלותה (`T* m_data`) שהוקצה עם `new[]`. הגרסאות שנוצרות אוטומטית על ידי המהדר יבצעו העתקה שטחית (shallow copy) של המצביע בלבד - שני עותקים יצביעו לאותו זיכרון, מה שיוביל ל-double free בהרס האובייקטים ול-aliasing (שינוי באחד ישפיע על השני). לו היה השדה מסוג STL/smart pointer (כגון `vector<T>` או `unique_ptr<T[]>`) - ברירות המחדל היו מספיקות.

