    int* m_buffer;
public:
    Widget(int size) : m_buffer(new int[size]) {}
    ~Widget() { delete[] m_buffer; }
    virtual void draw() const = 0;
};

class Button : public Widget {
    string* m_label;
public:
    Button(int size, const string& label)
        : Widget(size), m_label(new string(label)) {}
    ~Button() { delete m_label; }
    void draw() const override { cout << *m_label; }
};

void renderAll(const vector<Widget*>& widgets) {
    for (Widget* w : widgets) {
        w->draw();
        delete w;   // המחיקה מתבצעת דרך מצביע לבסיס
    }
}

int main() {
    vector<Widget*> widgets;
    widgets.push_back(new Button(10, "OK"));
    renderAll(widgets);
}
```

ענו על כל הסעיפים הבאים בצורה מנומקת:

**(א)** מהי ההתנהגות בפועל כאשר `renderAll` מבצע `delete w` על האובייקט מסוג `Button`, כאשר `~Widget()` **אינו** וירטואלי? הסבירו בדיוק אילו הרסנים נקראים (או לא נקראים), ומה הנזק הקונקרטי הנגרם בקוד הנתון (כולל השפעה על `m_label`).

**(ב)** התיקון הנפוץ הוא להוסיף `virtual` להרסן של `Widget`. הסבירו במונחי מנגנון השפה (vtable / dynamic dispatch) *מדוע* תיקון זה פותר את הבעיה — כלומר איך הקומפיילר/זמן-ריצה יודע כעת לקרוא ל-`~Button()` לפני `~Widget()` כאשר יש לנו רק מצביע מסוג `Widget*`.

**(ג)** נניח ש-`Widget` הוא מחלקה בסיס אבסטרקטית (יש בה מתודה טהורה `draw() const = 0`) שאף פעם לא מוחזק/נמחק דרך מצביע לבסיס במערכת (`renderAll` תמיד מקבל `vector<unique_ptr<Button>>` באופן קונקרטי, לא `Widget*`). האם עדיין חובה להצהיר על ההרסן כ-virtual? נמקו את תשובתכם, כולל האם קיים מחיר (overhead) לעשות זאת בכל זאת.

**(ד)** כעת נניח ש-`Widget` מנוהל אך ורק באמצעות `unique_ptr<Widget>` (ולא מצביעים גולמיים). האם זה משנה את התשובה לסעיף (א)? כלומר, האם `unique_ptr<Widget>` 'פותר' את הבעיה של הרסן לא-וירטואלי מבלי לשנות את `Widget`? נמקו.

נתונה המחלקה הבאה המנהלת מערך דינמי גולמי:

```cpp
class Buffer {
    int* data;
    size_t size;
public:
    Buffer(size_t n) : data(new int[n]), size(n) {}
    ~Buffer() { delete[] data; }
    // אין הגדרה מפורשת לבנאי/אופרטור העתקה, ואין הגדרה של בנאי/אופרטור העברה
};

void useBuffer(Buffer b) { /* ... */ }

int main() {
    Buffer b1(100);
    useBuffer(b1);              // (1)
    useBuffer(std::move(b1));   // (2)
}
```

ענו בקצרה על כל הסעיפים:

א. מה קורה בפועל בשורה (1)? האם הקוד מתקמפל, ואם כן - האם ההתנהגות שלו תקינה (safe) בזמן ריצה? נמקו בהתייחס לכלל השלוש (Rule of 3).

ב. מהי משמעות הקריאה ל-`std::move(b1)` בשורה (2)? האם `std::move` מבצע בפועל העברה של המשאב? הסבירו מה `std::move` עושה בפועל ברמת השפה.

ג. בהינתן שהמחלקה **לא** מגדירה בנאי העברה (move constructor) ולא אופרטור השמת-העברה (move assignment), האם שורה (2) עדיין מתקמפלת? מה קורה בפועל בזמן ריצה בשורה הזו, ומה מצבו של `b1` לאחר הקריאה?

ד. הוסיפו למחלקה `Buffer` בנאי העברה ואופרטור השמת-העברה תקינים ובטוחים (exception-safe, לא זולגים זיכרון), כך שלאחר קריאה ל-`std::move` על אובייקט המקור יישאר במצב תקין הניתן להריסה (`~Buffer`) בלי UB. הסבירו בקצרה גם מדוע לאחר הוספת בנאי/אופרטור ההעברה, קריאה כמו בשורה (2) הופכת ליעילה יותר משורה (1).

questions.model_solution:
### א. שורה (1) — `useBuffer(b1)`

המחלקה `Buffer` מחזיקה מצביע גולמי בבעלות (`int* data`) שהוקצה עם `new[]`, ואינה מגדירה בנאי העתקה, אופרטור השמת העתקה, בנאי העברה או אופרטור השמת העברה. לכן הקומפיילר מייצר עבורה **בנאי העתקה דיפולטיבי (shallow copy)**.

הקוד **מתקמפל**, כי `useBuffer` מקבל `Buffer` לפי ערך, ולכן `b1` מועתק לפרמטר `b` באמצעות בנאי ההעתקה הדיפולטיבי. אבל ההתנהגות **אינה בטוחה בזמן ריצה**: בנאי ההעתקה הדיפולטיבי מעתיק את המצביע `data` עצמו (לא את מה שהוא מצביע אליו), כך שגם `b1.data` וגם `b.data` מצביעים לאותו בלוק זיכרון. כאשר `useBuffer` מסתיים, ההרסן `~Buffer` של `b` מבצע `delete[]` על אותו זיכרון. בהמשך, כאשר `b1` נהרס (בסוף `main`), מתבצע `delete[]` **שני** על אותו מצביע — **double free**, שהיא התנהגות בלתי מוגדרת (UB).

זהו בדיוק המקרה הקלאסי מכלל השלוש (Rule of 3): מחלקה שמחזיקה מצביע גולמי בבעלות **חייבת** להגדיר בנאי העתקה עמוק, אופרטור השמת העתקה עמוק, והרסן — אחרת ברירת המחדל השטחית גורמת ל-aliasing ול-double free/dangling pointer.

### ב. משמעות `std::move(b1)`

`std::move` **אינו מזיז דבר בפועל**. זוהי פונקציה (בעצם, cast) שממירה את הביטוי `b1` לסוג **rvalue reference** (`Buffer&&`) — כלומר, היא רק "מתייגת" את `b1` כאובייקט שניתן "לשדוד" ממנו משאבים (an rvalue that may be moved from), מבלי לבצע כל פעולה בפועל על הזיכרון. ההעברה בפועל (אם קיימת) מתבצעת רק כאשר הביטוי המתויג מועבר לבנאי/אופרטור שמקבל `Buffer&&` — כלומר בנאי העברה או אופרטור השמת העברה, שמבצעים בפועל את "גניבת" המצביע.

### ג. אין בנאי/אופרטור העברה מוגדרים — מה קורה בשורה (2)?

כן, הקוד עדיין **מתקמפל**. הסיבה: כאשר אין overload תואם ל-`Buffer&&` (אין בנאי העברה מוגדר), resolution הקריאה נופל חזרה (fallback) על **בנאי ההעתקה** (`const Buffer&`), משום שקישור rvalue reference ל-`const Buffer&` הוא חוקי.

בפועל, אם כן, שורה (2) מבצעת בדיוק את אותה ההעתקה השטחית כמו בשורה (1) — הבנאי הדיפולטיבי מעתיק את המצביע `data`, ושוב מתקבל aliasing בין `b1.data` ל-`b.data`, ואותה בעיית double-free כשההרסנים רצים. כלומר, `std::move` כאן לא הועיל בכלום ולא שינה את הבטיחות/היעילות של הקריאה — `b1` עדיין "תקין" מבחינת הקומפיילר (לא רוקן) אבל האובייקט הכפול חולק את אותו זיכרון, מה שמוביל ל-UB בהרס.

### ד. הוספת בנאי העברה ואופרטור השמת-העברה בטוחים

```cpp
class Buffer {
    int* data;
    size_t size;
public:
    Buffer(size_t n) : data(new int[n]), size(n) {}

    // בנאי העתקה עמוק (Rule of 3 בעקבות הבעלות על data)
    Buffer(const Buffer& other) : data(new int[other.size]), size(other.size) {
        for (size_t i = 0; i < size; ++i) data[i] = other.data[i];
    }
    Buffer& operator=(const Buffer& other) {
        if (this == &other) return *this;
        int* newData = new int[other.size]; // הקצאה לפני שינוי מצב -> exception-safe
        for (size_t i = 0; i < other.size; ++i) newData[i] = other.data[i];
        delete[] data;
        data = newData;
        size = other.size;
        return *this;
    }

    // בנאי העברה: 'גונב' את המשאב ומשאיר את המקור במצב חוקי-להרס
    Buffer(Buffer&& other) noexcept : data(other.data), size(other.size) {
        other.data = nullptr;
        other.size = 0;
    }

    // אופרטור השמת-העברה
    Buffer& operator=(Buffer&& other) noexcept {
        if (this == &other) return *this;
        delete[] data;          // משחררים את מה שהיה לנו
        data = other.data;      // גונבים את המשאב
        size = other.size;
        other.data = nullptr;   // מנטרלים את המקור
        other.size = 0;
        return *this;
    }

    ~Buffer() { delete[] data; } // delete[] nullptr הוא no-op בטוח
};
```

כעת, שורה (2) בוחרת ב-overload resolution את **בנאי ההעברה** `Buffer(Buffer&&)` (כי `std::move(b1)` הוא rvalue reference, וקיים overload תואם עדיף על ה-const&). הבנאי מעתיק רק את המצביע (`data`) ואת `size` — **O(1)**, ללא הקצאת זיכרון וללא העתקת תוכן — ומאפס את `b1.data` ל-`nullptr`. כך:

- אין double-free: כשההרסן של `b1` ירוץ, הוא יקרא `delete[] nullptr` שהוא no-op בטוח.
- הקריאה יעילה משמעותית משורה (1): שורה (1) (העתקה עמוקה) עולה O(n) — הקצאת מערך חדש והעתקת n איברים — בעוד שורה (2) (העברה) עולה O(1) — רק החלפת שני מצביעים/סקלרים, ללא הקצאה כלל.

לכן `noexcept` על בנאי/אופרטור ההעברה חשוב גם מבחינה מעשית: הוא מאפשר ל-STL (למשל בעת `vector::resize`) להעדיף להשתמש בהעברה במקום בהעתקה גם כשנדרשת strong exception guarantee.
